{
  "terms": [
    {
      "term": "Resistance",
      "simpleDefinition": "The opposition to the flow of electric current through a conductor or component.",
      "anchor": "Like a narrow pipe restricting the flow of water.",
      "misconception": "Thinking resistance only exists in specific 'resistor' components; in reality, every cable and connection has some resistance."
    },
    {
      "term": "Resistivity",
      "simpleDefinition": "A fundamental property of a material that describes how strongly it opposes current, regardless of its shape or size.",
      "anchor": "The 'DNA' of the metal; copper has a lower resistivity than steel.",
      "misconception": "Believing that changing the length or thickness of a wire changes its resistivity; resistivity is fixed for the material itself."
    },
    {
      "term": "Voltage Drop",
      "simpleDefinition": "The loss of electrical pressure (voltage) as current passes through the resistance of a circuit.",
      "anchor": "The 'lost' voltage used up just to push electricity through the supply cables.",
      "misconception": "Assuming voltage drop only occurs during a fault; it happens in every working circuit due to cable resistance."
    },
    {
      "term": "Ohm (Ω)",
      "simpleDefinition": "The unit of measurement for electrical resistance.",
      "anchor": "The standard 'score' for how much a material fights against current.",
      "misconception": "Confusing the unit (Ohm) with the property (Resistance)."
    }
  ],
  "anchorPhrases": [
    "Resistance is the opposition to flow.",
    "Resistivity is a material property.",
    "Voltage drop is the loss of electrical pressure.",
    "Longer cables result in higher resistance."
  ],
  "misconceptionTargets": [
    "Resistance and resistivity are not the same thing.",
    "Voltage drop occurs in healthy circuits, not just faulty ones.",
    "Resistivity does not change when you cut a wire shorter."
  ]
}

{
  "teachChecks": [
    {
      "title": "The Nature of Resistance",
      "basicQuestions": [
        {
          "questionText": "What is the technical term for the opposition to the flow of electric current through a conductor?",
          "answerGuidance": [
            "Resistance",
            "Electrical resistance"
          ],
          "hint": "Think of the term that describes how a material fights against the flow of electricity.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the Greek symbol used to represent the Ohm?",
          "answerGuidance": [
            "Ω",
            "Omega"
          ],
          "hint": "It looks like a horseshoe.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Besides specific components like resistors, what part of a standard circuit path always possesses some resistance?",
          "answerGuidance": [
            "Cables",
            "Conductors",
            "Connections",
            "Wiring"
          ],
          "hint": "Consider the physical wires used to connect the circuit.",
          "sourceTeachingPointIds": [
            "TP3",
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why must an electrician consider the resistance of the supply cables even if no 'resistor' components are installed in the circuit?",
      "deeperAnswerGuidance": [
        "All conductors have natural resistance",
        "Cables are not perfect conductors",
        "Resistance is a physical reality for all conductive paths",
        "The wiring itself opposes current flow"
      ],
      "deeperSourceTeachingPointIds": [
        "TP3",
        "TP4"
      ],
      "hint": "Think about whether resistance is only found in specific parts or if it is a property of the entire conductive path."
    },
    {
      "title": "The Property of Resistivity",
      "basicQuestions": [
        {
          "questionText": "Which term describes the inherent property of a material to oppose current, regardless of its physical shape or size?",
          "answerGuidance": [
            "Resistivity"
          ],
          "hint": "This is the 'DNA' of the material itself.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP3"
          ]
        },
        {
          "questionText": "What Greek letter is used as the symbol for resistivity?",
          "answerGuidance": [
            "Rho",
            "ρ"
          ],
          "hint": "It looks like a small, rounded letter 'p'.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "If you cut a length of copper wire in half, what happens to the resistivity of the remaining piece of metal?",
          "answerGuidance": [
            "Stays the same",
            "Remains constant",
            "No change"
          ],
          "hint": "Does the type of metal change just because you changed its length?",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "How does resistivity allow an engineer to compare the quality of copper versus steel as a conductor without knowing the dimensions of the wires being used?",
      "deeperAnswerGuidance": [
        "Resistivity is independent of shape and size",
        "It is a fundamental material property",
        "It provides a constant value for comparison",
        "It describes the material's inherent opposition to current"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3",
        "TP4"
      ],
      "hint": "Focus on why resistivity is a 'constant' for a material while resistance is not."
    },
    {
      "title": "Resistance vs. Resistivity",
      "basicQuestions": [
        {
          "questionText": "If the length of a conductor is increased, what happens to its total resistance?",
          "answerGuidance": [
            "Increases",
            "Higher",
            "It goes up"
          ],
          "hint": "Think about the current having a longer path to travel through.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What happens to the resistance of a wire if its cross-sectional area (thickness) is increased?",
          "answerGuidance": [
            "Decreases",
            "Lower",
            "It goes down"
          ],
          "hint": "Think about a wider pipe allowing more flow.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Which value remains unchanged if you change the physical dimensions of a copper wire: Resistance or Resistivity?",
          "answerGuidance": [
            "Resistivity"
          ],
          "hint": "One is a total measurement of an object, the other is a property of the material.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why does a long, thin cable have a much higher resistance than a short, thick cable made of the same material?",
      "deeperAnswerGuidance": [
        "Increased length provides a longer path for current",
        "Smaller cross-sectional area provides less room for flow",
        "Resistance is determined by physical dimensions",
        "Length and area both negatively impact the total opposition"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP3"
      ],
      "hint": "Consider how both the distance traveled and the space available for the current affect the total opposition."
    },
    {
      "title": "The Concept of Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "What is the term for the loss of electrical pressure as current passes through the resistance of a circuit?",
          "answerGuidance": [
            "Voltage Drop"
          ],
          "hint": "It is the 'lost' voltage used up by the cables.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "In a working circuit, how does the voltage available at the load usually compare to the voltage at the source?",
          "answerGuidance": [
            "Lower",
            "Less",
            "Reduced"
          ],
          "hint": "Think about the pressure lost along the way.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Does voltage drop occur in a healthy, correctly functioning circuit?",
          "answerGuidance": [
            "Yes",
            "True"
          ],
          "hint": "Does every conductor have some resistance?",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is it impossible to have the exact same voltage at the end of a long cable as you have at the start while current is flowing?",
      "deeperAnswerGuidance": [
        "Energy is used to overcome the cable's resistance",
        "All conductors have some resistance",
        "Current flow through resistance always causes a drop",
        "Voltage is lost as it travels through the supply cables"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP4"
      ],
      "hint": "Think about the 'cost' or energy required to push electricity through a physical wire."
    },
    {
      "title": "Linking Resistivity to Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "What is the primary reason copper is preferred for electrical installations over materials with higher resistivity?",
          "answerGuidance": [
            "Lower voltage drop",
            "Efficiency",
            "Lower resistance"
          ],
          "hint": "Think about how much voltage is wasted in the cables.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "If a cable is made from a material with high resistivity, what effect does this have on the voltage drop?",
          "answerGuidance": [
            "Increases",
            "Higher",
            "Larger drop"
          ],
          "hint": "Higher resistivity leads to higher resistance.",
          "sourceTeachingPointIds": [
            "TP2",
            "TP3"
          ]
        },
        {
          "questionText": "Which physical property of a material must be low to ensure a cable has the lowest possible resistance for its size?",
          "answerGuidance": [
            "Resistivity"
          ],
          "hint": "This is the material-specific value represented by Rho.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "How does the choice of conductor material directly affect the amount of voltage available to power a piece of equipment?",
      "deeperAnswerGuidance": [
        "Material resistivity determines the cable's resistance",
        "Higher resistivity leads to higher resistance",
        "Higher resistance causes a larger voltage drop",
        "Material choice dictates how much voltage is lost in the cables"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP3"
      ],
      "hint": "Connect the material property to the cable's resistance, and then to the final voltage loss."
    }
  ]
}

{
  "integrative": {
    "title": "Material Choice and Circuit Performance",
    "objective": "Synthesize the relationship between resistivity, resistance, and voltage drop in a practical installation scenario.",
    "retrievalTextLines": [
      "A motor at the end of a long cable run is underperforming because the voltage reaching it is too low.",
      "The existing cable is made of a material with high resistivity.",
      "An electrician replaces it with a copper cable of identical length and cross-sectional area."
    ],
    "questionText": "Explain why switching to a material with lower resistivity (copper) increases the voltage available at the motor, even though the cable's length and thickness remain unchanged.",
    "answerGuidance": [
      "Copper has a lower resistivity (ρ) than the original material.",
      "Since resistivity is an inherent material property, a lower resistivity value results in a lower total resistance (R) for the same physical dimensions.",
      "Lower resistance in the supply cables reduces the amount of voltage drop occurring as current flows to the motor.",
      "Because less voltage is 'lost' overcoming the resistance of the cables, more electrical pressure (voltage) is available at the motor terminals."
    ],
    "hint": "Think about how the 'DNA' of the metal (resistivity) dictates the total opposition (resistance) and how that opposition 'steals' voltage before it reaches the load."
  }
}

